function getBlogPostById(id) {
  var numericId = Number(id);
  for (var i = 0; i < BLOG_POSTS.length; i++) {
    if (BLOG_POSTS[i].id === numericId) {
      return BLOG_POSTS[i];
    }
  }
  return null;
}

function getBlogPostBySlug(slug) {
  for (var i = 0; i < BLOG_POSTS.length; i++) {
    if (BLOG_POSTS[i].slug === slug) {
      return BLOG_POSTS[i];
    }
  }
  return null;
}
